  "inlineSchema": "// Synk Prisma Schema\n// Database structure for the unified saved content platform\n\ngenerator client {\n  provider        = \"prisma-client-js\"\n  output          = \"../generated/prisma\"\n  previewFeatures = [\"postgresqlExtensions\"]\n}\n\ndatasource db {\n  provider   = \"postgresql\"\n  url        = env(\"DATABASE_URL\")\n  extensions = [vector]\n}\n\n// ========================================\n// CORE MODELS\n// ========================================\n\nmodel SaveSession {\n  id   String  @id @default(cuid())\n  name String? // User can rename, null = auto-generated name\n\n  // Metadata\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // User relationship\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n  userId String\n\n  // Saves in this session\n  saves Save[]\n\n  // Folder organization\n  folder   Folder? @relation(fields: [folderId], references: [id], onDelete: SetNull)\n  folderId String?\n\n  // Status flags\n  isPinned   Boolean @default(false)\n  isLocked   Boolean @default(false)\n  isStarred  Boolean @default(false)\n  isArchived Boolean @default(false)\n  isPublic   Boolean @default(false)\n\n  // Soft delete support\n  deletedAt DateTime?\n\n  @@index([userId])\n  @@index([userId, createdAt])\n  @@index([folderId])\n}\n\nmodel Folder {\n  id    String  @id @default(cuid())\n  name  String\n  color String? // Hex color for folder icon\n  icon  String? // Emoji or icon name\n  order Int     @default(0)\n\n  // Hierarchy (optional nested folders)\n  parentId String?\n  parent   Folder?  @relation(\"FolderChildren\", fields: [parentId], references: [id], onDelete: Cascade)\n  children Folder[] @relation(\"FolderChildren\")\n\n  // User ownership\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  // Sessions in this folder\n  sessions SaveSession[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([userId])\n  @@index([userId, order])\n}\n\nmodel Save {\n  id      String  @id @default(cuid())\n  url     String\n  title   String\n  favicon String?\n  domain  String?\n\n  // Metadata\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Source tracking\n  source SaveSource @default(BROWSER)\n\n  // User relationship\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n  userId String\n\n  // Session grouping (optional for backward compatibility)\n  session   SaveSession? @relation(fields: [sessionId], references: [id], onDelete: SetNull)\n  sessionId String?\n\n  // Order within session for drag-and-drop\n  order Int @default(0)\n\n  // Optional category\n  category   Category? @relation(fields: [categoryId], references: [id])\n  categoryId String?\n\n  // Soft delete support\n  deletedAt DateTime?\n\n  // External Source Data (e.g. X/Twitter)\n  sourceId  String? // External ID (Tweet ID)\n  author    Json? // { name, handle, avatar }\n  metadata  Json? // { likes, retweets, mediaUrls }\n  embedding Unsupported(\"vector(768)\")?\n\n  tags Tag[]\n\n  @@index([userId])\n  @@index([userId, createdAt])\n  @@index([userId, source])\n  @@index([sessionId])\n  @@index([deletedAt])\n  @@index([sourceId])\n}\n\nmodel Tag {\n  id    String @id @default(cuid())\n  name  String @unique\n  saves Save[]\n}\n\nenum SaveSource {\n  BROWSER\n  X_LIKE\n  X_BOOKMARK\n  MOBILE_SHARE\n}\n\nenum Plan {\n  FREE\n  PRO\n}\n\nmodel Category {\n  id    String  @id @default(cuid())\n  name  String\n  slug  String\n  color String?\n\n  // System categories are predefined\n  isSystem Boolean @default(false)\n\n  saves Save[]\n\n  @@unique([slug])\n}\n\n// ========================================\n// AUTH MODELS (NextAuth.js)\n// ========================================\n\nmodel Account {\n  id                       String  @id @default(cuid())\n  userId                   String\n  type                     String\n  provider                 String\n  providerAccountId        String\n  refresh_token            String? @db.Text\n  access_token             String? @db.Text\n  expires_at               Int?\n  token_type               String?\n  scope                    String?\n  id_token                 String? @db.Text\n  session_state            String?\n  user                     User    @relation(fields: [userId], references: [id], onDelete: Cascade)\n  refresh_token_expires_in Int?\n\n  @@unique([provider, providerAccountId])\n}\n\nmodel Session {\n  id           String   @id @default(cuid())\n  sessionToken String   @unique\n  userId       String\n  expires      DateTime\n  user         User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n}\n\nmodel User {\n  id            String    @id @default(cuid())\n  name          String?\n  email         String?   @unique\n  emailVerified DateTime?\n  image         String?\n\n  // Subscription / Billing\n  plan             Plan    @default(FREE)\n  lsCustomerId     String? // LemonSqueezy customer ID\n  lsSubscriptionId String? // LemonSqueezy subscription ID\n\n  // Relationships\n  accounts     Account[]\n  sessions     Session[]\n  saves        Save[]\n  saveSessions SaveSession[]\n  folders      Folder[]\n  subscription Subscription?\n\n  // Usage tracking\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel Subscription {\n  id     String @id @default(cuid())\n  userId String @unique\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  // LemonSqueezy identifiers\n  lsSubscriptionId String @unique\n  lsCustomerId     String\n  lsVariantId      String\n\n  // Status tracking\n  status            String // active, cancelled, expired, past_due, paused\n  currentPeriodEnd  DateTime?\n  cancelAtPeriodEnd Boolean   @default(false)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([lsCustomerId])\n}\n\nmodel VerificationToken {\n  identifier String\n  token      String   @unique\n  expires    DateTime\n\n  @@unique([identifier, token])\n}\n\n// ========================================\n// WAITLIST\n// ========================================\n\nmodel Waitlist {\n  id        String   @id @default(cuid())\n  email     String\n  platform  String   @default(\"general\") // \"extension\", \"mobile\", \"general\"\n  userId    String?\n  createdAt DateTime @default(now())\n\n  @@unique([email, platform])\n  @@index([platform])\n}\n",
